import { useState, useEffect } from "react";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
  Title,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend, Title);

/**
 * BenchmarkResultsDashboard — Rich visualisation of FHE CNN benchmark results.
 *
 * Loads data from /benchmark_data.json (generated by scripts/csv_to_json.py).
 * Shows:
 *   1. Summary cards (accuracy, avg latency, total images)
 *   2. Accuracy comparison bar chart
 *   3. Per-layer timing breakdown (stacked bar)
 *   4. Per-digit accuracy heatmap
 *   5. Individual image results table
 *
 * When the 100-image benchmark finishes, just re-run csv_to_json.py
 * and the dashboard auto-updates.
 */

/* ── Colour palette ── */
const DEGREE_COLORS = {
  2: { bg: "#7b3ff2", light: "#7b3ff215", text: "#7b3ff2" },
  3: { bg: "#e68a00", light: "#e68a0015", text: "#e68a00" },
  4: { bg: "#e03e52", light: "#e03e5215", text: "#e03e52" },
};

const LAYER_COLORS = [
  "#0db7c4", // Encryption
  "#7b3ff2", // Conv1
  "#e68a00", // Act1
  "#f4b942", // Pool1
  "#9b6dff", // Conv2
  "#ff9f43", // Act2
  "#ffc857", // Pool2
  "#e03e52", // FC
  "#0aa35e", // Decryption
];

const TIMING_KEYS = [
  "encryption_ms", "conv1_ms", "act1_ms", "pool1_ms",
  "conv2_ms", "act2_ms", "pool2_ms", "fc_ms", "decryption_ms",
];

const formatMs = (ms) => {
  if (ms == null) return "—";
  if (ms >= 1000) return `${(ms / 1000).toFixed(1)}s`;
  return `${Math.round(ms)}ms`;
};

const accuracyColor = (pct) => {
  if (pct >= 80) return "#0aa35e";
  if (pct >= 40) return "#e68a00";
  return "#e03e52";
};

/* ══════════════════════════════════════════ */
export default function BenchmarkResultsDashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedDegree, setSelectedDegree] = useState(null); // for detail view

  useEffect(() => {
    fetch("/benchmark_data.json")
      .then((res) => {
        if (!res.ok) throw new Error("benchmark_data.json not found");
        return res.json();
      })
      .then((d) => {
        setData(d);
        setLoading(false);
      })
      .catch((err) => {
        setError(err.message);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-600" />
        <span className="ml-3 text-sm text-gray-500">Loading benchmark data…</span>
      </div>
    );
  }

  if (error) {
    return (
      <div className="rounded-lg p-6 text-center" style={{ background: "#fef2f2", border: "1px solid #fecaca" }}>
        <p className="text-sm text-red-600 font-medium">Could not load benchmark data</p>
        <p className="text-xs text-red-400 mt-1">{error}</p>
        <p className="text-xs text-gray-500 mt-3">
          Run <code className="bg-gray-100 px-1.5 py-0.5 rounded">python3 scripts/csv_to_json.py</code> to generate the data file.
        </p>
      </div>
    );
  }

  const { configs, raw_results } = data;
  const detailData = selectedDegree ? raw_results[`deg${selectedDegree}`] : null;

  return (
    <div className="space-y-6">
      {/* ═══ Header ═══ */}
      <div className="flex items-center justify-between">
        <div>
          <h3 className="text-base font-semibold" style={{ color: "#333" }}>
            FHE Benchmark Results
          </h3>
          <p className="text-xs mt-0.5" style={{ color: "#999" }}>
            {data.total_images} images · {data.library} · {data.scheme} scheme
          </p>
        </div>
        <div className="text-[10px] px-2.5 py-1 rounded-full" style={{ background: "#f0fdf4", color: "#0aa35e" }}>
          ● Data loaded
        </div>
      </div>

      {/* ═══ Summary Cards ═══ */}
      <div className="grid grid-cols-3 gap-3">
        {configs.map((cfg) => {
          const degColor = DEGREE_COLORS[cfg.degree] || DEGREE_COLORS[2];
          return (
            <button
              key={cfg.degree}
              onClick={() => setSelectedDegree(selectedDegree === cfg.degree ? null : cfg.degree)}
              className={`rounded-xl p-4 text-left transition-all border-2 hover:shadow-md ${
                selectedDegree === cfg.degree ? "shadow-lg scale-[1.02]" : ""
              }`}
              style={{
                background: "#fff",
                borderColor: selectedDegree === cfg.degree ? degColor.bg : "#e5e5e5",
              }}
            >
              <div className="text-[11px] font-medium uppercase tracking-wider" style={{ color: degColor.text }}>
                {cfg.label}
              </div>
              <div className="mt-2 flex items-end gap-2">
                <span
                  className="text-2xl font-bold"
                  style={{ color: accuracyColor(cfg.accuracy_pct) }}
                >
                  {cfg.accuracy_pct}%
                </span>
                <span className="text-xs mb-1" style={{ color: "#999" }}>
                  ({cfg.accuracy})
                </span>
              </div>
              <div className="mt-1.5 text-xs" style={{ color: "#666" }}>
                avg {formatMs(cfg.avg_total_ms)}
              </div>
              <div className="text-[10px] mt-0.5" style={{ color: "#bbb" }}>
                {cfg.num_images} images · {cfg.security}
              </div>
            </button>
          );
        })}
      </div>

      {/* ═══ Accuracy Comparison ═══ */}
      <div className="grid grid-cols-2 gap-4">
        {/* Accuracy bar chart */}
        <div className="rounded-xl p-4 bg-white border border-gray-200">
          <h4 className="text-xs font-medium uppercase tracking-wider mb-3" style={{ color: "#888" }}>
            Accuracy by Activation Degree
          </h4>
          <div style={{ height: 200 }}>
            <Bar
              data={{
                labels: configs.map((c) => c.label),
                datasets: [{
                  label: "Accuracy (%)",
                  data: configs.map((c) => c.accuracy_pct),
                  backgroundColor: configs.map((c) => (DEGREE_COLORS[c.degree] || DEGREE_COLORS[2]).bg),
                  borderRadius: 6,
                  barPercentage: 0.5,
                }],
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: { legend: { display: false } },
                scales: {
                  y: {
                    beginAtZero: true,
                    max: 100,
                    title: { display: true, text: "Accuracy (%)", font: { size: 10 } },
                    grid: { color: "#f5f5f5" },
                  },
                  x: { grid: { display: false } },
                },
              }}
            />
          </div>
        </div>

        {/* Average latency comparison */}
        <div className="rounded-xl p-4 bg-white border border-gray-200">
          <h4 className="text-xs font-medium uppercase tracking-wider mb-3" style={{ color: "#888" }}>
            Average Inference Time
          </h4>
          <div style={{ height: 200 }}>
            <Bar
              data={{
                labels: configs.map((c) => c.label),
                datasets: [{
                  label: "Avg Latency (ms)",
                  data: configs.map((c) => c.avg_total_ms),
                  backgroundColor: configs.map((c) => `${(DEGREE_COLORS[c.degree] || DEGREE_COLORS[2]).bg}90`),
                  borderColor: configs.map((c) => (DEGREE_COLORS[c.degree] || DEGREE_COLORS[2]).bg),
                  borderWidth: 2,
                  borderRadius: 6,
                  barPercentage: 0.5,
                }],
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                  legend: { display: false },
                  tooltip: {
                    callbacks: {
                      label: (ctx) => `${formatMs(ctx.raw)}`,
                    },
                  },
                },
                scales: {
                  y: {
                    beginAtZero: true,
                    title: { display: true, text: "Time (ms)", font: { size: 10 } },
                    grid: { color: "#f5f5f5" },
                  },
                  x: { grid: { display: false } },
                },
              }}
            />
          </div>
        </div>
      </div>

      {/* ═══ Per-Layer Timing Breakdown (Stacked Bar) ═══ */}
      <div className="rounded-xl p-4 bg-white border border-gray-200">
        <h4 className="text-xs font-medium uppercase tracking-wider mb-3" style={{ color: "#888" }}>
          Per-Layer Timing Breakdown
        </h4>
        <div style={{ height: 280 }}>
          <Bar
            data={{
              labels: configs.map((c) => c.label),
              datasets: configs[0].layer_labels.map((label, i) => ({
                label,
                data: configs.map((c) => c.layer_averages[TIMING_KEYS[i]]),
                backgroundColor: LAYER_COLORS[i],
              })),
            }}
            options={{
              responsive: true,
              maintainAspectRatio: false,
              plugins: {
                legend: {
                  position: "bottom",
                  labels: { boxWidth: 12, padding: 10, font: { size: 10 } },
                },
                tooltip: {
                  callbacks: {
                    label: (ctx) => `${ctx.dataset.label}: ${formatMs(ctx.raw)}`,
                    footer: (items) => {
                      const total = items.reduce((s, i) => s + i.raw, 0);
                      return `Total: ${formatMs(total)}`;
                    },
                  },
                },
              },
              scales: {
                x: { stacked: true, grid: { display: false } },
                y: {
                  stacked: true,
                  title: { display: true, text: "Time (ms)", font: { size: 11 } },
                  grid: { color: "#f0f0f0" },
                },
              },
            }}
          />
        </div>
      </div>

      {/* ═══ Per-Digit Accuracy Heatmap ═══ */}
      <div className="rounded-xl p-4 bg-white border border-gray-200">
        <h4 className="text-xs font-medium uppercase tracking-wider mb-3" style={{ color: "#888" }}>
          Per-Digit Accuracy
        </h4>
        <div className="overflow-x-auto">
          <table className="w-full text-xs">
            <thead>
              <tr>
                <th className="text-left px-3 py-2 font-medium" style={{ color: "#888" }}>Digit</th>
                {configs.map((c) => (
                  <th key={c.degree} className="text-center px-3 py-2 font-medium" style={{ color: "#888" }}>
                    {c.label}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {Array.from({ length: 10 }, (_, digit) => (
                <tr key={digit} className="border-t" style={{ borderColor: "#f0f0f0" }}>
                  <td className="px-3 py-2 font-mono font-bold" style={{ color: "#555" }}>
                    {digit}
                  </td>
                  {configs.map((c) => {
                    const d = c.per_digit_accuracy[String(digit)];
                    if (!d) return <td key={c.degree} className="text-center px-3 py-2 text-gray-300">—</td>;
                    return (
                      <td key={c.degree} className="text-center px-3 py-2">
                        <span
                          className="inline-block px-2 py-0.5 rounded-full font-medium"
                          style={{
                            background: `${accuracyColor(d.pct)}15`,
                            color: accuracyColor(d.pct),
                          }}
                        >
                          {d.correct}/{d.total}
                        </span>
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* ═══ Detail View (when a card is clicked) ═══ */}
      {selectedDegree && detailData && (
        <div className="rounded-xl p-4 bg-white border-2 transition-all"
          style={{ borderColor: (DEGREE_COLORS[selectedDegree] || DEGREE_COLORS[2]).bg }}
        >
          <div className="flex items-center justify-between mb-3">
            <h4 className="text-xs font-medium uppercase tracking-wider" style={{ color: "#888" }}>
              Individual Image Results — {configs.find((c) => c.degree === selectedDegree)?.label}
            </h4>
            <button
              onClick={() => setSelectedDegree(null)}
              className="text-xs text-gray-400 hover:text-gray-600 px-2 py-1"
            >
              ✕ Close
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-xs">
              <thead>
                <tr style={{ background: "#f8f8f8" }}>
                  <th className="px-2 py-2 text-left font-medium" style={{ color: "#888" }}>#</th>
                  <th className="px-2 py-2 text-center font-medium" style={{ color: "#888" }}>True</th>
                  <th className="px-2 py-2 text-center font-medium" style={{ color: "#888" }}>Predicted</th>
                  <th className="px-2 py-2 text-center font-medium" style={{ color: "#888" }}>Correct</th>
                  <th className="px-2 py-2 text-center font-medium" style={{ color: "#888" }}>Confidence</th>
                  <th className="px-2 py-2 text-right font-medium" style={{ color: "#888" }}>Total</th>
                  <th className="px-2 py-2 text-right font-medium" style={{ color: "#888" }}>Conv1</th>
                  <th className="px-2 py-2 text-right font-medium" style={{ color: "#888" }}>Conv2</th>
                  <th className="px-2 py-2 text-right font-medium" style={{ color: "#888" }}>FC</th>
                </tr>
              </thead>
              <tbody>
                {detailData.map((row) => (
                  <tr key={row.image_index} className="border-t hover:bg-gray-50" style={{ borderColor: "#f0f0f0" }}>
                    <td className="px-2 py-1.5 font-mono" style={{ color: "#999" }}>{row.image_index}</td>
                    <td className="px-2 py-1.5 text-center font-mono font-bold" style={{ color: "#333" }}>{row.true_label}</td>
                    <td className="px-2 py-1.5 text-center font-mono font-bold"
                      style={{ color: row.correct ? "#0aa35e" : "#e03e52" }}
                    >
                      {row.predicted}
                    </td>
                    <td className="px-2 py-1.5 text-center">
                      {row.correct ? "✓" : "✗"}
                    </td>
                    <td className="px-2 py-1.5 text-center font-mono" style={{ color: "#666" }}>
                      {(row.confidence * 100).toFixed(1)}%
                    </td>
                    <td className="px-2 py-1.5 text-right font-mono" style={{ color: "#333" }}>{formatMs(row.total_ms)}</td>
                    <td className="px-2 py-1.5 text-right font-mono" style={{ color: "#666" }}>{formatMs(row.conv1_ms)}</td>
                    <td className="px-2 py-1.5 text-right font-mono" style={{ color: "#666" }}>{formatMs(row.conv2_ms)}</td>
                    <td className="px-2 py-1.5 text-right font-mono" style={{ color: "#666" }}>{formatMs(row.fc_ms)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ═══ Key Findings ═══ */}
      <div className="rounded-xl p-4" style={{ background: "#fffbe6", border: "1px solid #ffe58f" }}>
        <p className="text-xs font-medium mb-1.5" style={{ color: "#ad6800" }}>
          Key Findings
        </p>
        <ul className="text-xs space-y-1" style={{ color: "#8c6200" }}>
          <li>• <b>x² (degree 2)</b> achieves {configs[0]?.accuracy_pct}% FHE accuracy — matching the activation used during training gives best results.</li>
          <li>• <b>Degree 3</b> drops to {configs[1]?.accuracy_pct}% accuracy — intermediate polynomial values overflow the plaintext modulus.</li>
          <li>• <b>Degree 4</b> drops to {configs[2]?.accuracy_pct}% accuracy — higher-degree terms cause complete signal corruption.</li>
          <li>• Convolution and FC layers dominate inference time ({">"}90% of total), activation function choice has minimal impact on latency.</li>
        </ul>
      </div>

      {/* ═══ Experiment Metadata ═══ */}
      <div className="text-[10px] flex flex-wrap gap-x-4 gap-y-1" style={{ color: "#bbb" }}>
        <span>EC2: t3.large (2 vCPU, 8 GB RAM + 16 GB swap)</span>
        <span>{data.library} ({data.scheme})</span>
        <span>p = {data.plaintext_modulus?.toLocaleString()}</span>
        <span>mult_depth = 6</span>
        <span>scale = {data.scale_factor}</span>
        <span>{data.total_images} images across {configs.length} configs</span>
      </div>
    </div>
  );
}
